#include<bits/stdc++.h>
using namespace std;
string s;
int x,a;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>x>>s;
	int l=s.size()-1;
	a=0;
	for(int i=0; i<s.size(); i++) {
		int v;
		if(isupper(s[i]))v=s[i]-'A'+10;
		else v=s[i]-'0';
		a+=v*pow(x,l);
		l--;
	}
	cout<<a;
	return 0;
}
